func teamFor(data CreateTabData, colorClass string) []string {
	if colorClass == "blue-team" {
		return data.BlueTeam
	}
	return data.RedTeam
}

func joinNames(names []string) string {
	out := ""
	for i, n := range names {
		if i > 0 {
			out += ","
		}
		out += n
	}
	return out
}

