func benchX(i, total int, fromRight bool) float64 {
	denom := float64(total - 1)
	if denom < 1 {
		denom = 1
	}
	offset := (float64(i) / denom) * (courtW * 0.35)
	if fromRight {
		return courtW - offset
	}
	return offset
}

